const input = $json.body ?? $json;
const prompt = input.prompt;

if (!prompt || typeof prompt !== 'string') {
  throw new Error('Поле prompt отсутствует или не является строкой');
}

// В self-hosted n8n доступ к $env в Code node часто заблокирован.
// Поэтому модель берем из входного payload (input.model) либо из fallback.
const model = (input.model || 'llama3.1:8b').toString();

return [{
  json: {
    prompt,
    model,
    projectTitle: input.projectTitle || '',
    sourceText: input.sourceText || '',
    departments: Array.isArray(input.departments) ? input.departments : []
  }
}];

