const data = $json;
const raw = data?.message?.content || data?.response || data?.output || '';

if (!raw || typeof raw !== 'string') {
  throw new Error('Ollama не вернул текстовый ответ');
}

let text = raw.trim();
text = text.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim();

const firstBrace = text.indexOf('{');
const lastBrace = text.lastIndexOf('}');
if (firstBrace < 0 || lastBrace < 0) {
  throw new Error('В ответе модели не найден JSON объект');
}

const parsed = JSON.parse(text.slice(firstBrace, lastBrace + 1));

if (!parsed.summary || !Array.isArray(parsed.tasks) || !Array.isArray(parsed.departmentSuggestions)) {
  throw new Error('JSON не соответствует ожидаемой схеме');
}

return [{ json: parsed }];
